/* Metadata Panel */
.metadata-panel {
  width: 320px;
  background: white;
  border-left: 1px solid #e0e0e0;
  overflow-y: auto;
  flex-shrink: 0;
}

.metadata-header {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 12px 16px;
  border-bottom: 1px solid #e0e0e0;
}

.metadata-header h3 {
  font-size: 0.95rem;
  margin: 0;
}

.metadata-close {
  background: none;
  border: none;
  font-size: 1.2rem;
  cursor: pointer;
  color: #666;
  padding: 0 4px;
}

.metadata-type {
  display: inline-block;
  font-size: 0.7rem;
  padding: 2px 8px;
  border-radius: 3px;
  color: white;
  font-weight: 600;
  margin: 8px 16px 0;
}

.metadata-fields {
  padding: 8px 16px 16px;
}

.metadata-field {
  padding: 6px 0;
  border-bottom: 1px solid #f0f0f0;
}

.metadata-field-key {
  font-size: 0.72rem;
  color: #888;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.metadata-field-value {
  font-size: 0.85rem;
  color: #333;
  margin-top: 2px;
  word-break: break-all;
}

.metadata-neighbors {
  padding: 0 16px 16px;
}

.metadata-neighbors h4 {
  font-size: 0.8rem;
  color: #666;
  margin-bottom: 8px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.neighbor-item {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 4px 0;
  cursor: pointer;
  font-size: 0.82rem;
  color: #2563eb;
}

.neighbor-item:hover {
  text-decoration: underline;
}

.neighbor-direction {
  font-size: 0.7rem;
  color: #aaa;
  width: 16px;
}

.neighbor-label-tag {
  font-size: 0.65rem;
  color: #888;
  background: #f0f0f0;
  padding: 1px 4px;
  border-radius: 2px;
}

/* Legend */
.legend {
  position: absolute;
  bottom: 12px;
  left: 12px;
  background: rgba(255,255,255,0.95);
  border-radius: 6px;
  padding: 10px 14px;
  box-shadow: 0 2px 8px rgba(0,0,0,0.1);
  z-index: 10;
}

.legend h4 {
  font-size: 0.72rem;
  color: #666;
  margin-bottom: 6px;
  text-transform: uppercase;
  letter-spacing: 0.5px;
}

.legend-item {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 2px 0;
  font-size: 0.78rem;
  color: #444;
}

.legend-dot {
  width: 10px;
  height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
}

/* React Flow overrides */
.react-flow__node {
  font-size: 11px;
}

.react-flow__edge-text {
  font-size: 9px;
}

/* Custom node */
.custom-node {
  padding: 6px 10px;
  border-radius: 6px;
  border: 2px solid;
  font-size: 11px;
  font-weight: 500;
  text-align: center;
  min-width: 80px;
  max-width: 150px;
  white-space: nowrap;
  overflow: hidden;
