  1→import React, { useMemo, useCallback } from 'react';
  2→import {
  3→  ReactFlow,
  4→  Background,
  5→  Controls,
  6→  useNodesState,
  7→  useEdgesState,
  8→  MarkerType,
  9→} from '@xyflow/react';
 10→import '@xyflow/react/dist/style.css';
 11→import NODE_COLORS from './nodeColors';
 12→
 13→// Simple layout: arrange by type in columns
 14→const TYPE_COLUMNS = {
 15→  Customer: 0,
 16→  SalesOrder: 1,
 17→  Product: 2,
 18→  Plant: 3,
 19→  Delivery: 4,
 20→  BillingDocument: 5,
 21→  Payment: 6,
 22→};
 23→
 24→function layoutNodes(visibleNodes, allNodes) {
 25→  const nodeMap = new Map();
 26→  allNodes.forEach(n => nodeMap.set(n.id, n));
 27→
 28→  // Group by type
 29→  const groups = {};
 30→  for (const id of visibleNodes) {
 31→    const node = nodeMap.get(id);
 32→    if (!node) continue;
 33→    if (!groups[node.type]) groups[node.type] = [];
 34→    groups[node.type].push(node);
 35→  }
 36→
 37→  const flowNodes = [];
 38→  const COL_WIDTH = 220;
 39→  const ROW_HEIGHT = 60;
 40→
 41→  for (const [type, nodes] of Object.entries(groups)) {
 42→    const col = TYPE_COLUMNS[type] ?? 0;
 43→    nodes.forEach((node, idx) => {
 44→      const colors = NODE_COLORS[node.type] || { bg: '#f3f4f6', border: '#666', text: '#333' };
 45→      flowNodes.push({
 46→        id: node.id,
 47→        position: { x: col * COL_WIDTH, y: idx * ROW_HEIGHT },
 48→        data: { label: node.label, nodeData: node },
 49→        style: {
 50→          background: colors.bg,
 51→          border: `2px solid ${colors.border}`,
 52→          color: colors.text,
 53→          borderRadius: 6,
 54→          padding: '6px 10px',
 55→          fontSize: 11,
 56→          fontWeight: 500,
 57→          minWidth: 80,
 58→          maxWidth: 180,
 59→          textOverflow: 'ellipsis',
 60→          overflow: 'hidden',
 61→          whiteSpace: 'nowrap',
 62→        },
 63→      });
 64→    });
 65→  }
 66→  return flowNodes;
 67→}
 68→
 69→function GraphView({ graphData, visibleNodes, selectedNodeId, onNodeClick }) {
 70→  const flowNodes = useMemo(() => {
 71→    return layoutNodes(visibleNodes, graphData.nodes);
 72→  }, [visibleNodes, graphData.nodes]);
 73→
 74→  const flowEdges = useMemo(() => {
 75→    return graphData.edges
 76→      .filter(e => visibleNodes.has(e.source) && visibleNodes.has(e.target))
 77→      .map((e, i) => ({
 78→        id: `e-${i}`,
 79→        source: e.source,
 80→        target: e.target,
 81→        label: e.label,
 82→        type: 'default',
 83→        animated: false,
 84→        style: { stroke: '#94a3b8', strokeWidth: 1.5 },
 85→        labelStyle: { fontSize: 9, fill: '#64748b' },
 86→        markerEnd: { type: MarkerType.ArrowClosed, width: 12, height: 12, color: '#94a3b8' },
 87→      }));
 88→  }, [visibleNodes, graphData.edges]);
 89→
 90→  const [nodes, setNodes, onNodesChange] = useNodesState(flowNodes);
 91→  const [edges, setEdges, onEdgesChange] = useEdgesState(flowEdges);
 92→
 93→  // Sync when visibleNodes change
 94→  React.useEffect(() => {
 95→    setNodes(flowNodes);
 96→    setEdges(flowEdges);
 97→  }, [flowNodes, flowEdges, setNodes, setEdges]);
 98→
 99→  const handleNodeClick = useCallback((event, node) => {
100→    if (node.data?.nodeData) {
101→      onNodeClick(node.data.nodeData);
102→    }
103→  }, [onNodeClick]);
104→
105→  return (
106→    <ReactFlow
107→      nodes={nodes}
108→      edges={edges}
109→      onNodesChange={onNodesChange}
110→      onEdgesChange={onEdgesChange}
111→      onNodeClick={handleNodeClick}
112→      fitView
113→      fitViewOptions={{ padding: 0.2 }}
114→      minZoom={0.1}
115→      maxZoom={3}
116→      proOptions={{ hideAttribution: true }}
117→    >
118→      <Background color="#e2e8f0" gap={20} />
119→      <Controls />
120→    </ReactFlow>
121→  );
122→}
123→
124→export default GraphView;
125→

 1→import React, { useState, useRef, useEffect } from 'react';
 2→import NODE_COLORS from './nodeColors';
 3→
 4→function SearchBar({ nodes, onSelect }) {
 5→  const [query, setQuery] = useState('');
 6→  const [results, setResults] = useState([]);
 7→  const [open, setOpen] = useState(false);
 8→  const ref = useRef();
 9→
10→  useEffect(() => {
11→    function handleClick(e) {
12→      if (ref.current && !ref.current.contains(e.target)) setOpen(false);
13→    }
14→    document.addEventListener('mousedown', handleClick);
15→    return () => document.removeEventListener('mousedown', handleClick);
16→  }, []);
17→
18→  const handleChange = (e) => {
19→    const q = e.target.value;
20→    setQuery(q);
21→    if (q.length < 2) { setResults([]); setOpen(false); return; }
22→    const lower = q.toLowerCase();
23→    const matches = nodes
24→      .filter(n => n.label.toLowerCase().includes(lower) || n.id.toLowerCase().includes(lower) ||
25→        (n.metadata && Object.values(n.metadata).some(v => String(v).toLowerCase().includes(lower))))
26→      .slice(0, 20);
27→    setResults(matches);
28→    setOpen(matches.length > 0);
29→  };
30→
31→  return (
32→    <div className="search-bar" ref={ref}>
33→      <input
34→        placeholder="Search by ID, name, or keyword..."
35→        value={query}
36→        onChange={handleChange}
37→        onFocus={() => results.length > 0 && setOpen(true)}
38→      />
39→      {open && (
40→        <div className="search-results">
41→          {results.map(n => (
42→            <div key={n.id} className="search-result-item" onClick={() => {
43→              onSelect(n.id);
44→              setOpen(false);
45→              setQuery('');
46→            }}>
47→              <span className="search-type-badge" style={{ background: NODE_COLORS[n.type]?.border || '#666' }}>
48→                {n.type}
49→              </span>
50→              <span className="search-result-label">{n.label}</span>
51→            </div>
52→          ))}
53→        </div>
54→      )}
55→    </div>
56→  );
57→}
58→
59→export default SearchBar;
