 1→import React, { useState, useEffect } from 'react';
 2→import GraphView from './components/GraphView';
 3→import SearchBar from './components/SearchBar';
 4→import MetadataPanel from './components/MetadataPanel';
 5→import Legend from './components/Legend';
 6→import './App.css';
 7→
 8→function App() {
 9→  const [graphData, setGraphData] = useState(null);
10→  const [selectedNode, setSelectedNode] = useState(null);
11→  const [visibleNodes, setVisibleNodes] = useState(new Set());
12→  const [loading, setLoading] = useState(true);
13→
14→  useEffect(() => {
15→    fetch('/graph-data.json')
16→      .then(r => r.json())
17→      .then(data => {
18→        setGraphData(data);
19→        // Start with just customer nodes visible
20→        const initial = new Set();
21→        data.nodes.filter(n => n.type === 'Customer').forEach(n => initial.add(n.id));
22→        setVisibleNodes(initial);
23→        setLoading(false);
24→      });
25→  }, []);
26→
27→  const expandNode = (nodeId) => {
28→    if (!graphData) return;
29→    const neighbors = graphData.adjacency[nodeId] || [];
30→    setVisibleNodes(prev => {
31→      const next = new Set(prev);
32→      next.add(nodeId);
33→      neighbors.forEach(n => next.add(n.node));
34→      return next;
35→    });
36→  };
37→
38→  const focusNode = (nodeId) => {
39→    if (!graphData) return;
40→    const neighbors = graphData.adjacency[nodeId] || [];
41→    const next = new Set();
42→    next.add(nodeId);
43→    neighbors.forEach(n => next.add(n.node));
44→    setVisibleNodes(next);
45→    setSelectedNode(graphData.nodes.find(n => n.id === nodeId) || null);
46→  };
47→
48→  if (loading) {
49→    return <div className="loading">Loading SAP O2C Graph...</div>;
50→  }
51→
52→  return (
53→    <div className="app">
54→      <header className="app-header">
55→        <h1>SAP Order-to-Cash Graph</h1>
56→        <SearchBar nodes={graphData.nodes} onSelect={focusNode} />
57→      </header>
58→      <div className="app-body">
59→        <div className="graph-container">
60→          <GraphView
61→            graphData={graphData}
62→            visibleNodes={visibleNodes}
63→            selectedNodeId={selectedNode?.id}
64→            onNodeClick={(node) => {
65→              setSelectedNode(node);
66→              expandNode(node.id);
67→            }}
68→          />
69→          <Legend />
70→        </div>
71→        {selectedNode && (
72→          <MetadataPanel
73→            node={selectedNode}
74→            neighbors={graphData.adjacency[selectedNode.id] || []}
75→            onClose={() => setSelectedNode(null)}
76→            onNavigate={focusNode}
77→          />
78→        )}
79→      </div>
80→    </div>
81→  );
82→}
83→
84→export default App;
