  1→/**
  2→ * Reads SAP O2C JSONL data and produces a graph JSON file.
  3→ * Output: public/graph-data.json with { nodes, edges, index }
  4→ */
  5→const fs = require('fs');
  6→const path = require('path');
  7→
  8→const DATA_DIR = path.resolve(__dirname, '../../sap-o2c-data');
  9→const OUT_FILE = path.resolve(__dirname, '../public/graph-data.json');
 10→
 11→// --- Helpers ---
 12→
 13→function readJsonl(folder) {
 14→  const dir = path.join(DATA_DIR, folder);
 15→  if (!fs.existsSync(dir)) return [];
 16→  const files = fs.readdirSync(dir).filter(f => f.endsWith('.jsonl'));
 17→  const records = [];
 18→  for (const file of files) {
 19→    const lines = fs.readFileSync(path.join(dir, file), 'utf8').split('\n').filter(Boolean);
 20→    for (const line of lines) {
 21→      try { records.push(JSON.parse(line)); } catch {}
 22→    }
 23→  }
 24→  return records;
 25→}
 26→
 27→// --- Load all tables ---
 28→console.log('Loading data...');
 29→const salesOrderHeaders = readJsonl('sales_order_headers');
 30→const salesOrderItems = readJsonl('sales_order_items');
 31→const deliveryHeaders = readJsonl('outbound_delivery_headers');
 32→const deliveryItems = readJsonl('outbound_delivery_items');
 33→const billingHeaders = readJsonl('billing_document_headers');
 34→const billingItems = readJsonl('billing_document_items');
 35→const payments = readJsonl('payments_accounts_receivable');
 36→const journalEntries = readJsonl('journal_entry_items_accounts_receivable');
 37→const businessPartners = readJsonl('business_partners');
 38→const bpAddresses = readJsonl('business_partner_addresses');
 39→const products = readJsonl('products');
 40→const productDescs = readJsonl('product_descriptions');
 41→const plants = readJsonl('plants');
 42→
 43→console.log(`Loaded: ${salesOrderHeaders.length} SOs, ${deliveryHeaders.length} deliveries, ${billingHeaders.length} invoices, ${journalEntries.length} journal entries, ${businessPartners.length} BPs, ${products.length} products, ${plants.length} plants`);
 44→
 45→// --- Build lookup maps ---
 46→const productDescMap = {};
 47→for (const pd of productDescs) {
 48→  if (pd.language === 'EN') productDescMap[pd.product] = pd.productDescription;
 49→}
 50→
 51→const bpAddressMap = {};
 52→for (const addr of bpAddresses) {
 53→  if (!bpAddressMap[addr.businessPartner]) bpAddressMap[addr.businessPartner] = addr;
 54→}
 55→
 56→// --- Build nodes ---
 57→const nodes = [];
 58→const nodeSet = new Set();
 59→
 60→function addNode(id, type, label, metadata) {
 61→  if (nodeSet.has(id)) return;
 62→  nodeSet.add(id);
 63→  nodes.push({ id, type, label, metadata });
 64→}
 65→
 66→// Customers
 67→for (const bp of businessPartners) {
 68→  const id = `customer-${bp.businessPartner}`;
 69→  const name = bp.businessPartnerFullName || bp.organizationBpName1 || bp.businessPartner;
 70→  const addr = bpAddressMap[bp.businessPartner];
 71→  addNode(id, 'Customer', name, {
 72→    businessPartner: bp.businessPartner,
 73→    customer: bp.customer,
 74→    name,
 75→    category: bp.businessPartnerCategory,
 76→    grouping: bp.businessPartnerGrouping,
 77→    blocked: bp.businessPartnerIsBlocked,
 78→    city: addr?.cityName || '',
 79→    region: addr?.region || '',
 80→    country: addr?.country || '',
 81→  });
 82→}
 83→
 84→// Plants
 85→for (const p of plants) {
 86→  addNode(`plant-${p.plant}`, 'Plant', p.plantName || p.plant, {
 87→    plant: p.plant,
 88→    name: p.plantName,
 89→    salesOrganization: p.salesOrganization,
 90→  });
 91→}
 92→
 93→// Products (only those referenced in sales orders to keep graph manageable)
 94→const usedProducts = new Set();
 95→for (const item of salesOrderItems) {
 96→  if (item.material) usedProducts.add(item.material);
 97→}
 98→for (const p of products) {
 99→  if (!usedProducts.has(p.product)) continue;
100→  const desc = productDescMap[p.product] || p.product;
101→  addNode(`product-${p.product}`, 'Product', desc, {
102→    product: p.product,
103→    description: desc,
104→    productType: p.productType,
105→    productGroup: p.productGroup,
106→    baseUnit: p.baseUnit,
107→  });
108→}
109→
110→// Sales Orders
111→for (const so of salesOrderHeaders) {
112→  addNode(`so-${so.salesOrder}`, 'SalesOrder', `SO ${so.salesOrder}`, {
113→    salesOrder: so.salesOrder,
114→    type: so.salesOrderType,
115→    creationDate: so.creationDate,
116→    totalNetAmount: so.totalNetAmount,
117→    currency: so.transactionCurrency,
118→    deliveryStatus: so.overallDeliveryStatus,
119→    billingStatus: so.overallOrdReltdBillgStatus,
120→    paymentTerms: so.customerPaymentTerms,
121→  });
122→}
123→
124→// Deliveries
125→for (const d of deliveryHeaders) {
126→  addNode(`del-${d.deliveryDocument}`, 'Delivery', `DEL ${d.deliveryDocument}`, {
127→    deliveryDocument: d.deliveryDocument,
128→    creationDate: d.creationDate,
129→    goodsMovementStatus: d.overallGoodsMovementStatus,
130→    pickingStatus: d.overallPickingStatus,
131→    shippingPoint: d.shippingPoint,
132→    actualGoodsMovementDate: d.actualGoodsMovementDate,
133→  });
134→}
135→
136→// Billing Documents
137→for (const b of billingHeaders) {
138→  addNode(`bill-${b.billingDocument}`, 'BillingDocument', `INV ${b.billingDocument}`, {
139→    billingDocument: b.billingDocument,
140→    type: b.billingDocumentType,
141→    date: b.billingDocumentDate,
142→    totalNetAmount: b.totalNetAmount,
143→    currency: b.transactionCurrency,
144→    cancelled: b.billingDocumentIsCancelled,
145→    accountingDocument: b.accountingDocument,
146→  });
147→}
148→
149→// Payments (from journal entries where referenceDocument links to billing)
150→// Group journal entries by accountingDocument to create unique payment nodes
151→const paymentDocs = new Map();
152→for (const je of journalEntries) {
153→  const key = `${je.companyCode}-${je.fiscalYear}-${je.accountingDocument}`;
154→  if (!paymentDocs.has(key)) {
155→    paymentDocs.set(key, {
156→      accountingDocument: je.accountingDocument,
157→      companyCode: je.companyCode,
158→      fiscalYear: je.fiscalYear,
159→      documentType: je.accountingDocumentType,
160→      customer: je.customer,
161→      postingDate: je.postingDate,
162→      referenceDocuments: new Set(),
163→      totalAmount: 0,
164→      currency: je.transactionCurrency,
165→      clearingDocument: je.clearingAccountingDocument,
166→    });
167→  }
168→  const doc = paymentDocs.get(key);
169→  if (je.referenceDocument) doc.referenceDocuments.add(je.referenceDocument);
170→  doc.totalAmount += parseFloat(je.amountInTransactionCurrency) || 0;
171→}
172→
173→for (const [key, doc] of paymentDocs) {
174→  addNode(`pay-${doc.accountingDocument}`, 'Payment', `ACC ${doc.accountingDocument}`, {
175→    accountingDocument: doc.accountingDocument,
176→    companyCode: doc.companyCode,
177→    fiscalYear: doc.fiscalYear,
178→    documentType: doc.documentType,
179→    customer: doc.customer,
180→    postingDate: doc.postingDate,
181→    totalAmount: Math.round(doc.totalAmount * 100) / 100,
182→    currency: doc.currency,
183→  });
184→}
185→
186→// --- Build edges ---
187→const edges = [];
188→const edgeSet = new Set();
189→
190→function addEdge(source, target, label) {
191→  const key = `${source}->${target}`;
192→  if (edgeSet.has(key)) return;
193→  if (!nodeSet.has(source) || !nodeSet.has(target)) return;
194→  edgeSet.add(key);
195→  edges.push({ source, target, label });
196→}
197→
198→// Customer -> SalesOrder (places)
199→for (const so of salesOrderHeaders) {
200→  if (so.soldToParty) {
201→    addEdge(`customer-${so.soldToParty}`, `so-${so.salesOrder}`, 'places');
202→  }
203→}
204→
205→// SalesOrder -> Product (contains)
206→for (const item of salesOrderItems) {
207→  if (item.material) {
208→    addEdge(`so-${item.salesOrder}`, `product-${item.material}`, 'contains');
209→  }
210→}
211→
212→// SalesOrder -> Plant (ships_from)
213→const soPlantDone = new Set();
214→for (const item of salesOrderItems) {
215→  if (item.productionPlant) {
216→    const key = `${item.salesOrder}-${item.productionPlant}`;
217→    if (!soPlantDone.has(key)) {
218→      soPlantDone.add(key);
219→      addEdge(`so-${item.salesOrder}`, `plant-${item.productionPlant}`, 'ships_from');
220→    }
221→  }
222→}
223→
224→// SalesOrder -> Delivery (fulfilled_by)
225→for (const di of deliveryItems) {
226→  if (di.referenceSdDocument) {
227→    addEdge(`so-${di.referenceSdDocument}`, `del-${di.deliveryDocument}`, 'fulfilled_by');
228→  }
229→}
230→
231→// Delivery -> BillingDocument (billed_in)
232→for (const bi of billingItems) {
233→  if (bi.referenceSdDocument) {
234→    addEdge(`del-${bi.referenceSdDocument}`, `bill-${bi.billingDocument}`, 'billed_in');
235→  }
236→}
237→
238→// BillingDocument -> Payment (via journal entries referenceDocument)
239→for (const [key, doc] of paymentDocs) {
240→  for (const refDoc of doc.referenceDocuments) {
241→    if (nodeSet.has(`bill-${refDoc}`)) {
242→      addEdge(`bill-${refDoc}`, `pay-${doc.accountingDocument}`, 'accounted_in');
243→    }
244→  }
245→}
246→
247→// Customer -> Payment
248→for (const [key, doc] of paymentDocs) {
249→  if (doc.customer) {
250→    addEdge(`customer-${doc.customer}`, `pay-${doc.accountingDocument}`, 'pays');
251→  }
252→}
253→
254→// Customer -> BillingDocument (billed_to)
255→for (const b of billingHeaders) {
256→  if (b.soldToParty) {
257→    addEdge(`customer-${b.soldToParty}`, `bill-${b.billingDocument}`, 'billed_to');
258→  }
259→}
260→
261→// --- Build adjacency index for fast neighbor lookups ---
262→const adjacency = {};
263→for (const edge of edges) {
264→  if (!adjacency[edge.source]) adjacency[edge.source] = [];
265→  if (!adjacency[edge.target]) adjacency[edge.target] = [];
266→  adjacency[edge.source].push({ node: edge.target, label: edge.label, direction: 'out' });
267→  adjacency[edge.target].push({ node: edge.source, label: edge.label, direction: 'in' });
268→}
269→
270→// --- Output ---
271→const graph = { nodes, edges, adjacency };
272→fs.writeFileSync(OUT_FILE, JSON.stringify(graph));
273→console.log(`\nGraph built: ${nodes.length} nodes, ${edges.length} edges`);
274→console.log('Node types:', [...new Set(nodes.map(n => n.type))].map(t => `${t}: ${nodes.filter(n => n.type === t).length}`).join(', '));
275→console.log(`Written to ${OUT_FILE}`);
