import React, { useState, useRef, useEffect } from 'react';

function QueryPanel({ onClose }) {
  const [input, setInput] = useState('');
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [expandedData, setExpandedData] = useState(null);
  const historyRef = useRef(null);

  useEffect(() => {
    if (historyRef.current) {
      historyRef.current.scrollTop = historyRef.current.scrollHeight;
    }
  }, [history, loading]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const q = input.trim();
    if (!q || loading) return;

    setInput('');
    setHistory(prev => [...prev, { role: 'user', content: q }]);
    setLoading(true);
    setExpandedData(null);

    try {
      const res = await fetch('/query', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ query: q }),
      });
      const data = await res.json();
      setHistory(prev => [...prev, {
        role: 'assistant',
        content: data.answer,
        data: data.data,
        sql: data.sql,
      }]);
    } catch (err) {
      setHistory(prev => [...prev, {
        role: 'assistant',
        content: 'Failed to connect to the backend. Make sure the server is running on port 3001.',
        data: [],
      }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="query-panel">
      <div className="query-panel-header">
        <h3>Ask a Question</h3>
        <button className="query-panel-close" onClick={onClose}>&times;</button>
      </div>

      <div className="query-history" ref={historyRef}>
        {history.length === 0 && (
          <div className="query-empty">
            <p>Ask questions about your SAP O2C data:</p>
            <div className="query-suggestions">
              {[
                'How many sales orders are there?',
                'Top 5 customers by order value',
                'Show cancelled billing documents',
                'Which products have the most orders?',
              ].map((q, i) => (
                <button key={i} className="query-suggestion" onClick={() => setInput(q)}>{q}</button>
              ))}
            </div>
          </div>
        )}

        {history.map((msg, i) => (
          <div key={i} className={`query-msg query-msg-${msg.role}`}>
            <div className="query-msg-label">{msg.role === 'user' ? 'You' : 'Assistant'}</div>
            <div className="query-msg-content">{msg.content}</div>
            {msg.role === 'assistant' && msg.data && msg.data.length > 0 && (
              <button
                className="query-data-toggle"
                onClick={() => setExpandedData(expandedData === i ? null : i)}
              >
                {expandedData === i ? 'Hide data' : `Show data (${msg.data.length} rows)`}
              </button>
            )}
            {expandedData === i && msg.data && (
              <div className="query-data-table-wrap">
                <table className="query-data-table">
                  <thead>
                    <tr>
                      {Object.keys(msg.data[0]).map(k => <th key={k}>{k}</th>)}
                    </tr>
                  </thead>
                  <tbody>
                    {msg.data.slice(0, 20).map((row, ri) => (
                      <tr key={ri}>
                        {Object.values(row).map((v, ci) => <td key={ci}>{v != null ? String(v) : ''}</td>)}
                      </tr>
                    ))}
                  </tbody>
                </table>
                {msg.data.length > 20 && (
                  <div className="query-data-more">Showing 20 of {msg.data.length} rows</div>
                )}
              </div>
            )}
            {msg.role === 'assistant' && msg.sql && (
              <details className="query-sql-details">
                <summary>SQL</summary>
                <pre className="query-sql">{msg.sql}</pre>
              </details>
            )}
          </div>
        ))}

        {loading && (
          <div className="query-msg query-msg-assistant">
            <div className="query-msg-label">Assistant</div>
            <div className="query-loading-dots">Thinking<span className="dots">...</span></div>
          </div>
        )}
      </div>

      <form className="query-input-form" onSubmit={handleSubmit}>
        <input
          className="query-input"
          value={input}
          onChange={e => setInput(e.target.value)}
          placeholder="Ask about sales orders, deliveries, billing..."
          disabled={loading}
        />
        <button className="query-submit" type="submit" disabled={loading || !input.trim()}>
          Send
        </button>
      </form>
    </div>
  );
}

export default QueryPanel;

