import React, { useState, useRef, useEffect } from 'react';

function QueryPanel({ onClose }) {
  const [input, setInput] = useState('');
  const [history, setHistory] = useState([]);
  const [loading, setLoading] = useState(false);
  const [expandedData, setExpandedData] = useState(null);
  const historyRef = useRef(null);

  useEffect(() => {
    if (historyRef.current) {
      historyRef.current.scrollTop = historyRef.current.scrollHeight;
    }
  }, [history, loading]);

  const handleSubmit = async (e) => {
    e.preventDefault();
    const q = input.trim();
    if (!q || loading) return;

    setInput('');
    setHistory(prev => [...prev, { role: 'user', content: q }]);
    setLoading(true);
    setExpandedData(null);

    try {
      const res = await fetch('/query', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ query: q }),
      });
      const data = await res.json();
      setHistory(prev => [...prev, {
        role: 'assistant',
        content: data.answer,
        data: data.data,
        sql: data.sql,
      }]);
    } catch (err) {
      setHistory(prev => [...prev, {
        role: 'assistant',
        content: 'Failed to connect to the backend. Make sure the server is running on port 3001.',
        data: [],
      }]);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="chat-panel">
      {/* Header */}
      <div className="chat-header">
        <div className="chat-header-left">
          <span className="chat-header-title">Chat with Graph</span>
          <span className="chat-header-subtitle">Order to Cash</span>
