.typing-dot:nth-child(3) { animation-delay: 0.3s; }

@keyframes typingBounce {
  0%, 60%, 100% { transform: translateY(0); opacity: 0.4; }
  30% { transform: translateY(-4px); opacity: 1; }
}

/* Suggestions */
.chat-suggestions {
  display: flex;
  flex-direction: column;
  gap: 6px;
  padding: 0 4px;
  margin-bottom: 16px;
}

.chat-suggestion {
  background: white;
  border: 1px solid #e0e0e0;
  border-radius: 10px;
  padding: 9px 14px;
  font-size: 0.8rem;
  color: #555;
  cursor: pointer;
  text-align: left;
  transition: all 0.15s;
}

.chat-suggestion:hover {
  background: #f5f5f5;
  border-color: #ccc;
  color: #111;
}

/* Data toggle / table */
.chat-data-toggle {
  display: inline-block;
  margin-top: 8px;
  font-size: 0.75rem;
  color: #2563eb;
  background: none;
  border: none;
  cursor: pointer;
  padding: 0;
}

.chat-data-toggle:hover {
  text-decoration: underline;
}

.chat-data-table-wrap {
  margin-top: 8px;
  overflow-x: auto;
  max-height: 220px;
  overflow-y: auto;
  border: 1px solid #e0e0e0;
  border-radius: 8px;
  max-width: 92%;
}

.chat-data-table {
  width: 100%;
  border-collapse: collapse;
  font-size: 0.72rem;
}

.chat-data-table th {
  background: #f7f7f7;
  padding: 5px 8px;
  text-align: left;
  font-weight: 600;
  border-bottom: 1px solid #e0e0e0;
  white-space: nowrap;
  position: sticky;
  top: 0;
}

.chat-data-table td {
  padding: 4px 8px;
  border-bottom: 1px solid #f0f0f0;
  white-space: nowrap;
}

.chat-data-more {
  font-size: 0.7rem;
  color: #888;
  padding: 4px 8px;
  text-align: center;
}

.chat-sql-details {
  margin-top: 8px;
  font-size: 0.75rem;
  max-width: 92%;
}

.chat-sql-details summary {
  cursor: pointer;
  color: #999;
  font-size: 0.72rem;
}

.chat-sql {
  margin-top: 4px;
  background: #1a1a2e;
  color: #a5f3fc;
  padding: 10px;
  border-radius: 8px;
  font-size: 0.72rem;
  overflow-x: auto;
  white-space: pre-wrap;
  word-break: break-all;
}

/* Status bar */
.chat-status {
  display: flex;
  align-items: center;
  gap: 6px;
  padding: 8px 20px;
  border-top: 1px solid #eee;
  background: white;
}

.chat-status-dot {
  width: 7px;
  height: 7px;
  border-radius: 50%;
  background: #22c55e;
  flex-shrink: 0;
}

.chat-status-dot.thinking {
  background: #f59e0b;
  animation: pulse 1s ease-in-out infinite;
}

@keyframes pulse {
  0%, 100% { opacity: 1; }
  50% { opacity: 0.4; }
}

.chat-status-text {
  font-size: 0.72rem;
  color: #888;
}

/* Input area */
.chat-input-form {
  display: flex;
  padding: 12px 16px 16px;
  background: white;
  gap: 8px;
  align-items: center;
}

.chat-input {
  flex: 1;
  padding: 10px 14px;
  border: 1px solid #e0e0e0;
  border-radius: 10px;
  font-size: 0.85rem;
  outline: none;
  background: #f7f7f7;
  transition: border-color 0.15s, background 0.15s;
}

.chat-input:focus {
  border-color: #ccc;
  background: white;
}

.chat-input::placeholder {
  color: #aaa;
}

.chat-send {
  padding: 9px 18px;
  background: #1a1a2e;
  color: white;
  border: none;
  border-radius: 10px;
  font-size: 0.82rem;
  font-weight: 500;
  cursor: pointer;
  transition: background 0.15s;
}

.chat-send:disabled {
  opacity: 0.35;
  cursor: not-allowed;
}

.chat-send:not(:disabled):hover {
  background: #2d2d4e;
}

